mapper.select:
SELECT idx
from hotel_kiosk.reservations
where reservation_id = #{reservationId}

mapper.update:
update hotel_kiosk.reservations
set pay_status = #{payStatus}
where idx = #{idx}

UPDATE hotel_kiosk.reservations
SET sms_status = #{smsStatus}
WHERE idx = #{idx}

mapper.select:
SELECT *
FROM hotel_kiosk.members
WHERE member_phone = #{memberPhone}
  AND member_birth = #{memberBirth};

mapper.update:
update hotel_kiosk.members
set member_point = member_point - #{pointAmount}
where member_phone = #{memberPhone} and member_birth = #{memberBirth}

UPDATE hotel_kiosk.members
SET member_point = member_point + #{earnPoint}
WHERE member_phone = #{memberPhone}
  AND member_birth = #{memberBirth}
